+    fn leaf_accepts_egress_morphism() {
+        let mut morphism = derived_view_morphism();
+        morphism.class = MorphismClass::Egress;
+        let bridge = FederationBridge::new(
+            FederationRole::LeafFabric(LeafConfig::default()),
